import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.index.IndexResponse;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.CreateIndexRequest;
import org.elasticsearch.client.indices.CreateIndexResponse;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.TermsAggregationBuilder;
import org.elasticsearch.search.aggregations.metrics.AvgAggregationBuilder;
import org.elasticsearch.search.aggregations.metrics.MaxAggregationBuilder;
import org.elasticsearch.search.aggregations.metrics.MinAggregationBuilder;
import org.elasticsearch.search.aggregations.metrics.SumAggregationBuilder;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.*;

@SpringBootApplication
@RestController
@RequestMapping("/api/products")
public class EcommerceSearchApplication {

    @Autowired
    private RestHighLevelClient client;

    public static void main(String[] args) {
        SpringApplication.run(EcommerceSearchApplication.class, args);
    }

    @PostMapping("/index")
    public String indexProduct(@RequestBody Product product) throws IOException {
        IndexRequest request = new IndexRequest("products");
        request.id(product.getId().toString());
        request.source(product.toJson(), XContentType.JSON);
        IndexResponse response = client.index(request, RequestOptions.DEFAULT);
        return response.getId();
    }

    @GetMapping("/search")
    public SearchResponse searchProducts(@RequestParam String query,
                                       @RequestParam(defaultValue = "0") int from,
                                       @RequestParam(defaultValue = "10") int size,
                                       @RequestParam(required = false) String[] categories,
                                       @RequestParam(required = false) Double minPrice,
                                       @RequestParam(required = false) Double maxPrice) throws IOException {
        SearchRequest searchRequest = new SearchRequest("products");
        SearchSourceBuilder searchSourceBuilder = new SearchSourceBuilder();
        searchSourceBuilder.from(from);
        searchSourceBuilder.size(size);

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();
        boolQuery.must(QueryBuilders.multiMatchQuery(query, "name", "description", "brand"));

        if (categories != null && categories.length > 0) {
            boolQuery.filter(QueryBuilders.termsQuery("category", categories));
        }

        if (minPrice != null) {
            boolQuery.filter(QueryBuilders.rangeQuery("price").gte(minPrice));
        }

        if (maxPrice != null) {
            boolQuery.filter(QueryBuilders.rangeQuery("price").lte(maxPrice));
        }

        searchSourceBuilder.query(boolQuery);

        // Faceted navigation aggregations
        TermsAggregationBuilder categoryAgg = AggregationBuilders.terms("categories").field("category").size(100);
        TermsAggregationBuilder brandAgg = AggregationBuilders.terms("brands").field("brand").size(100);
        MinAggregationBuilder minPriceAgg = AggregationBuilders.min("min_price").field("price");
        MaxAggregationBuilder maxPriceAgg = AggregationBuilders.max("max_price").field("price");
        AvgAggregationBuilder avgPriceAgg = AggregationBuilders.avg("avg_price").field("price");
        SumAggregationBuilder totalSalesAgg = AggregationBuilders.sum("total_sales").field("sales");

        searchSourceBuilder.aggregation(categoryAgg);
        searchSourceBuilder.aggregation(brandAgg);
        searchSourceBuilder.aggregation(minPriceAgg);
        searchSourceBuilder.aggregation(maxPriceAgg);
        searchSourceBuilder.aggregation(avgPriceAgg);
        searchSourceBuilder.aggregation(totalSalesAgg);

        searchRequest.source(searchSourceBuilder);
        return client.search(searchRequest, RequestOptions.DEFAULT);
    }

    @GetMapping("/autocomplete")
    public List<String> autoComplete(@RequestParam String prefix) throws IOException {
        SearchRequest searchRequest = new SearchRequest("products");
        SearchSourceBuilder searchSourceBuilder = new SearchSourceBuilder();
        searchSourceBuilder.size(10);
        searchSourceBuilder.query(QueryBuilders.prefixQuery("name", prefix));
        searchRequest.source(searchSourceBuilder);
        SearchResponse response = client.search(searchRequest, RequestOptions.DEFAULT);
        List<String> suggestions = new ArrayList<>();
        // Process suggestions from response
        return suggestions;
    }

    @PostMapping("/query")
    public void saveQuery(@RequestBody SearchQuery query) throws IOException {
        IndexRequest request = new IndexRequest("search_queries");
        request.id(UUID.randomUUID().toString());
        request.source(query.toJson(), XContentType.JSON);
        client.index(request, RequestOptions.DEFAULT);
    }

    @Bean
    public RestHighLevelClient elasticsearchClient() {
        return new RestHighLevelClient(
                org.elasticsearch.client.RestClient.builder(
                        new org.apache.http.HttpHost("localhost", 9200)
                )
        );
    }

    @PostConstruct
    public void createIndex() throws IOException {
        CreateIndexRequest request = new CreateIndexRequest("products");
        String mapping = "{\n" +
                "  \"mappings\": {\n" +
                "    \"properties\": {\n" +
                "      \"id\": {\"type\": \"integer\"},\n" +
                "      \"name\": {\"type\": \"text\", \"analyzer\": \"standard\"},\n" +
                "      \"description\": {\"type\": \"text\", \"analyzer\": \"standard\"},\n" +
                "      \"price\": {\"type\": \"float\"},\n" +
                "      \"category\": {\"type\": \"keyword\"},\n" +
                "      \"brand\": {\"type\": \"keyword\"},\n" +
                "      \"tags\": {\"type\": \"keyword\"},\n" +
                "      \"sales\": {\"type\": \"integer\"},\n" +
                "      \"inStock\": {\"type\": \"boolean\"}\n" +
                "    }\n" +
                "  }\n" +
                "}";
        request.mapping(mapping, XContentType.JSON);
        CreateIndexResponse response = client.indices().create(request, RequestOptions.DEFAULT);
    }
}

class Product {
    private Integer id;
    private String name;
    private String description;
    private Double price;
    private String category;
    private String brand;
    private List<String> tags;
    private Integer sales;
    private Boolean inStock;

    public Product() {}

    public Product(Integer id, String name, String description, Double price, String category, String brand, List<String> tags, Integer sales, Boolean inStock) {
        this.id = id;
        this.name = name;
        this.description = description;
        this.price = price;
        this.category = category;
        this.brand = brand;
        this.tags = tags;
        this.sales = sales;
        this.inStock = inStock;
    }

    public String toJson() {
        return "{\n" +
                "  \"id\": " + id + ",\n" +
                "  \"name\": \"" + name + "\",\n" +
                "  \"description\": \"" + description + "\",\n" +
                "  \"price\": " + price + ",\n" +
                "  \"category\": \"" + category + "\",\n" +
                "  \"brand\": \"" + brand + "\",\n" +
                "  \"tags\": " + tags + ",\n" +
                "  \"sales\": " + sales + ",\n" +
                "  \"inStock\": " + inStock + "\n" +
                "}";
    }

    // Getters and setters
    public Integer getId() { return id; }
    public void setId(Integer id) { this.id = id; }
    public String getName() { return name; }
    public void setName(String name) { this.name = name; }
    public String getDescription() { return description; }
    public void setDescription(String description) { this.description = description; }
    public Double getPrice() { return price; }
    public void setPrice(Double price) { this.price = price; }
    public String getCategory() { return category; }
    public void setCategory(String category) { this.category = category; }
    public String getBrand() { return brand; }
    public void setBrand(String brand) { this.brand = brand; }
    public List<String> getTags() { return tags; }
    public void setTags(List<String> tags) { this.tags = tags; }
    public Integer getSales() { return sales; }
    public void setSales(Integer sales) { this.sales = sales; }
    public Boolean getInStock() { return inStock; }
    public void setInStock(Boolean inStock) { this.inStock = inStock; }
}

class SearchQuery {
    private String query;
    private Date timestamp;
    private String userId;
    private Map<String, Object> filters;

    public SearchQuery() {
        this.timestamp = new Date();
    }

    public SearchQuery(String query, String userId, Map<String, Object> filters) {
        this();
        this.query = query;
        this.userId = userId;
        this.filters = filters;
    }

    public String toJson() {
        return "{\n" +
                "  \"query\": \"" + query + "\",\n" +
                "  \"timestamp\": \"" + timestamp + "\",\n" +
                "  \"userId\": \"" + userId + "\",\n" +
                "  \"filters\": " + filters + "\n" +
                "}";
    }

    // Getters and setters
    public String getQuery() { return query; }
    public void setQuery(String query) { this.query = query; }
    public Date getTimestamp() { return timestamp; }
    public void setTimestamp(Date timestamp) { this.timestamp = timestamp; }
    public String getUserId() { return userId; }
    public void setUserId(String userId) { this.userId = userId; }
    public Map<String, Object> getFilters() { return filters; }
    public void setFilters(Map<String, Object> filters) { this.filters = filters; }
}